solution: ```class Solution {
public:
    bool possibleBipartition(int n, vector<vector<int>>& dislikes) {
        vector<vector<int>> g(n + 1);
        for (auto& d : dislikes) {
            int a = d[0], b = d[1];
            g[a].push_back(b);
            g[b].push_back(a);
        }
        vector<int> color(n + 1, 0);
        queue<int> q;
        for (int i = 1; i <= n; ++i) {
            if (color[i] != 0) continue;
            color[i] = 1;
            q.push(i);
            while (!q.empty()) {
                int u = q.front(); q.pop();
                for (int v : g[u]) {
                    if (color[v] == 0) {
                        color[v] = -color[u];
                        q.push(v);
                    } else if (color[v] == color[u]) {
                        return false;
                    }
                }
            }
        }
        return true;
    }
};
